import React, { useState, useEffect } from 'react';

function CustomParallax({ scrollPercentage, largeLayers, mediumLayers, smallLayers }) {
  const [showScrollHint, setShowScrollHint] = useState(true);
  const [prevScrollY, setPrevScrollY] = useState(0);

  useEffect(() => {
    const handleScroll = () => {
      const currentScrollY = window.scrollY;
      setShowScrollHint(currentScrollY <= prevScrollY);
      setPrevScrollY(currentScrollY);
    };

    window.addEventListener('scroll', handleScroll);

    return () => {
      window.removeEventListener('scroll', handleScroll);
    };
  }, [prevScrollY]);

  const chooseLayersByResolution = () => {
    const windowWidth = window.innerWidth;
    if (windowWidth >= 769) {
      return largeLayers;
    } else if (windowWidth >= 577) {
      return mediumLayers;
    } else {
      return smallLayers;
    }
  };

  const chosenLayers = chooseLayersByResolution();

  return (
    <div className="CustomParallax" style={{ position: 'relative', overflow: 'hidden' }}>
      <div className="ScrollHint" style={{
        position: 'fixed',
        top: showScrollHint ? '25%' : '-100px', // Mueve el mensaje fuera de la pantalla si showScrollHint es false
        left: '50%',
        transform: 'translateX(-50%)',
        zIndex: 9999,
        textAlign: 'center',
        color: '#fff',
        transition: 'top 0.3s ease-in-out' // Agrega una transición suave al cambio de posición
      }}>
        <p>Desplázate hacia abajo</p>
        <div className="ArrowDown"></div>
      </div>
      {chosenLayers.map((layer, index) => (
        <div
          key={index}
          className={`Layer${index + 1}`}
          style={{
            backgroundImage: `url('${layer.image}')`,
            backgroundPositionX: `calc(${scrollPercentage * layer.speed}% + ${layer.offset})`,
          }}
        ></div>
      ))}
    </div>
  );
}

export default CustomParallax;
